#include <iostream>
#include <mysql/mysql.h>

int main() {
    MYSQL* conn;
    char query[256];

    // Connect to MySQL database
    conn = mysql_init(NULL);
    if (!mysql_real_connect(conn, "localhost", "root", "MySecretPass123", "demo", 0, NULL, 0)) {
        std::cerr << "Error: Unable to connect to MySQL." << std::endl;
        return 1;
    }

    // Create a table
    sprintf(query, "CREATE TABLE IF NOT EXISTS users (id INT PRIMARY KEY, name VARCHAR(255))");
    if (mysql_query(conn, query) != 0) {
        std::cerr << "Error: Unable to create table." << std::endl;
        return 1;
    }

    // Insert a row into the table
    sprintf(query, "INSERT INTO users (id, name) VALUES (%d, '%s')", 1, "John Doe");
    if (mysql_query(conn, query) != 0) {
        std::cerr << "Error: Unable to insert row." << std::endl;
        return 1;
    }

    // Select data from the table
    sprintf(query, "SELECT * FROM users");
    if (mysql_query(conn, query) != 0) {
        std::cerr << "Error: Unable to select data." << std::endl;
        return 1;
    }

    // Print the results
    MYSQL_RES* res = mysql_store_result(conn);
    while ((row = mysql_fetch_row(res))) {
        for (int i = 0; i < mysql_num_fields(res); i++) {
            printf("%s ", row[i] ? row[i] : "NULL");
        }
        printf("\n");
    }

    // Close the connection
    mysql_close(conn);

    return 0;
}